public class GameController {
    private RoomMap map;
    private Player player;
    private PuzzleView view;
    private boolean isRunning;

    public GameController() {
        map = new RoomMap();
        player = new Player();
        view = new PuzzleView();
        isRunning = true;
    }

    public void run() {
        map.generateRooms();
        map.loadPuzzles("puzzles.txt");

        view.showMessage("GGC Plague Puzzle Demo");
        view.showMessage("Type a room ID with a puzzle: R1, R2, R4, R5, R8, R12, R13");
        view.showMessage("Type quit to stop.\n");

        while (isRunning) {
            String roomId = view.getInput("Enter room ID: ");

            if (roomId.equalsIgnoreCase("quit")) {
                isRunning = false;
                view.showMessage("Game ended.");
                break;
            }

            if (!player.enterRoom(roomId, map)) {
                view.showMessage("Room not found.\n");
                continue;
            }

            Room currentRoom = player.getCurrentRoom(map);
            view.showRoom(currentRoom);

            if (!currentRoom.checkPuzzle()) {
                view.showMessage("No puzzle in this room.\n");
                continue;
            }

            boolean puzzleMenuRunning = true;

            while (puzzleMenuRunning) {
                view.puzzleUI(currentRoom);
                String action = view.getInput("Action: ");

                switch (action.toLowerCase()) {
                    case "explore":
                    case "explore puzzle":
                        player.explorePuzzle(currentRoom, view);
                        break;

                    case "solve":
                    case "solve puzzle":
                        player.solvePuzzle(currentRoom, view);

                        puzzleMenuRunning = currentRoom.checkPuzzle()
                                && currentRoom.getPuzzle().getAttemptsRemaining() > 0;   if (puzzle != null && puzzle.getAttemptsRemaining() <= 0) {
                                puzzleMenuRunning = false;
                            }
                        }
                        break;

                    case "ignore":
                    case "ignore puzzle":
                        player.ignorePuzzle(view);
                        puzzleMenuRunning = false;
                        break;

                    default:
                        view.showMessage("Invalid puzzle command.");
                }
            }

            if (!currentRoom.getItems().isEmpty()) {
                view.showMessage("Items currently in room: " + currentRoom.getItems());
            }

            view.showMessage("");
        }
    }
}

public class GameController {
    private RoomMap map;
    private Player player;
    private PuzzleView view;
    private boolean isRunning;

    public GameController() {
        map = new RoomMap();
        player = new Player();
        view = new PuzzleView();
        isRunning = true;
    }

    public void run() {
        map.generateRooms();
        map.loadPuzzles("Puzzle");

        view.showMessage("GGC Plague Puzzle Demo");
        view.showMessage("Type a room ID with a puzzle: R1, R2, R4, R5, R8, R12, R13");
        view.showMessage("Type quit to stop.\n");

        while (isRunning) {
            String roomId = view.getInput("Enter room ID: ");

            if (roomId.equalsIgnoreCase("quit")) {
                isRunning = false;
                view.showMessage("Game ended.");
                break;
            }

            if (!player.enterRoom(roomId, map)) {
                view.showMessage("Room not found.\n");
                continue;
            }

            Room currentRoom = player.getCurrentRoom(map);
            view.showRoom(currentRoom);

            if (!currentRoom.checkPuzzle()) {
                view.showMessage("No puzzle in this room.\n");
                continue;
            }

            boolean puzzleMenuRunning = true;

            while (puzzleMenuRunning) {
                view.puzzleUI(currentRoom);
                String action = view.getInput("Action: ");

                switch (action.toLowerCase()) {
                    case "explore":
                    case "explore puzzle":
                        player.explorePuzzle(currentRoom, view);
                        break;

                    case "solve":
                    case "solve puzzle":
                        player.solvePuzzle(currentRoom, view);

                        Puzzle puzzle = currentRoom.getPuzzle();
                        puzzleMenuRunning = puzzle != null
                                && !puzzle.isSolved()
                                && puzzle.getAttemptsRemaining() > 0;
                        break;

                    case "ignore":
                    case "ignore puzzle":
                        player.ignorePuzzle(view);
                        puzzleMenuRunning = false;
                        break;

                    default:
                        view.showMessage("Invalid puzzle command.");
                }
            }

            if (!currentRoom.getItems().isEmpty()) {
                view.showMessage("Items currently in room: " + currentRoom.getItems());
            }

            view.showMessage("");
        }
    }
}

import java.util.Scanner;

public class PuzzleView {
    private Scanner scanner;

    public PuzzleView() {
        scanner = new Scanner(System.in);
    }

    public void puzzleUI() {
        System.out.println("\n********************************");
        System.out.println("[Explore Puzzle] - Read the riddle");
        System.out.println("[Solve]          - Input an answer");
        System.out.println("[Ignore Puzzle]  - Leave for later");
        System.out.println("********************************");
    }

    public void displayPuzzle(Puzzle puzzle) {
        System.out.println("\n==============================");
        System.out.println("PUZZLE: " + puzzle.getPuzzleName());
        System.out.println("==============================");
        System.out.println("Question: " + puzzle.getQuestion());
        System.out.println("Hint: " + puzzle.getHint());
        System.out.println("Attempts Remaining: " + puzzle.getAttemptsRemaining());
        System.out.println("==============================");
    }

    public String getPlayerAnswer() {
        System.out.print("Enter your answer: ");
        return scanner.nextLine();
    }

    public void showCorrectMessage() {
        System.out.println("Correct! You solved the puzzle.");
    }

    public void showIncorrectMessage(int attemptsRemaining) {
        System.out.println("Incorrect answer.");
        System.out.println("Attempts Remaining: " + attemptsRemaining);
    }

    public void showPuzzleFailed() {
        System.out.println("You failed the puzzle. No attempts left.");
    }

    public void showReward(String reward) {
        System.out.println("Reward dropped: " + reward);
    }

    public void showMessage(String message) {
        System.out.println(message);
    }
}

import java.util.Scanner;

public class PuzzleView {
    private Scanner scanner;

    public PuzzleView() {
        scanner = new Scanner(System.in);
    }

    public void puzzleUI() {
        System.out.println("\n********************************");
        System.out.println("[Explore Puzzle] - Read the riddle");
        System.out.println("[Solve]          - Input an answer");
        System.out.println("[Ignore Puzzle]  - Leave for later");
        System.out.println("********************************");
    }

    public void puzzleUI(Room room) {
        if (room != null && room.getPuzzle() != null) {
            System.out.println("\nPuzzle in room " + room.getRoomId() + " (attempts: "
                    + room.getPuzzle().getAttemptsRemaining() + ")");
        }
        puzzleUI();
    }

    public void displayPuzzle(Puzzle puzzle) {
        System.out.println("\n==============================");
        System.out.println("PUZZLE: " + puzzle.getPuzzleName());
        System.out.println("==============================");
        System.out.println("Question: " + puzzle.getQuestion());
        System.out.println("Hint: " + puzzle.getHint());
        System.out.println("Attempts Remaining: " + puzzle.getAttemptsRemaining());
        System.out.println("==============================");
    }

    public String getPlayerAnswer() {
        System.out.print("Enter your answer: ");
        return scanner.nextLine();
    }

    public String getInput(String prompt) {
        System.out.print(prompt);
        return scanner.nextLine();
    }

    public void showRoom(Room room) {
        if (room == null) {
            showMessage("No room selected.");
            return;
        }
        showMessage("You entered room: " + room.getRoomId());
    }

    public void showCorrectMessage() {
        System.out.println("Correct! You solved the puzzle.");
    }

    public void showIncorrectMessage(int attemptsRemaining) {
        System.out.println("Incorrect answer.");
        System.out.println("Attempts Remaining: " + attemptsRemaining);
    }

    public void showPuzzleFailed() {
        System.out.println("You failed the puzzle. No attempts left.");
    }

    public void showReward(String reward) {
        System.out.println("Reward dropped: " + reward);
    }

    public void showMessage(String message) {
        System.out.println(message);
    }
}
